function seedSeverityByEntity(
  changedEntities: EntityChange[],
): Map<string, { raw: number; factor: string | null }> {
  const map = new Map<string, { raw: number; factor: string | null }>()

  for (const ec of changedEntities) {
    const raw = CHANGE_SEVERITY[ec.changeKind] ?? 0
    const existing = map.get(ec.entity.id)
    if (existing && existing.raw >= raw) continue
    map.set(ec.entity.id, {
      raw,
      factor: `upstream ${ec.changeKind.replace(/_/g, ' ')} in ${ec.entity.name}`,
    })
  }

  return map
}

function upstreamSeverityForEntry(
  entry: BlastRadiusEntry,
  seedSeverity: Map<string, { raw: number; factor: string | null }>,
  fallbackWorst: { score: number; factor: string | null },
): { score: number; factor: string | null } {
  const seed = seedSeverity.get(entry.seedId)
  if (!seed) return fallbackWorst
  return { score: Math.round(seed.raw * 0.5), factor: seed.factor }
}

function worstUpstreamSeverity(
  changedEntities: EntityChange[],
): { score: number; factor: string | null } {
  let worst = 0
  let factor: string | null = null

  for (const ec of changedEntities) {
    const s = CHANGE_SEVERITY[ec.changeKind] ?? 0
    if (s > worst) {
      worst = s
      factor = `upstream ${ec.changeKind.replace(/_/g, ' ')} in ${ec.entity.name}`
    }
  }

  return { score: Math.round(worst * 0.5), factor }
}

function uniqueFactors(factors: string[]): string[] {
  return Array.from(new Set(factors))
}

function contractCoverageAdjustment(
  entityChange: EntityChange,
  blastEntries: BlastRadiusEntry[],
  changedEntityIds: Set<string>,
): { delta: number; factor: string | null } {
  if (!CONTRACT_CHANGE_KINDS.has(entityChange.changeKind)) {
    return { delta: 0, factor: null }
  }

  const directDependents = new Set(
    blastEntries
      .filter(entry => entry.seedId === entityChange.entity.id && entry.depth === 1)
      .map(entry => entry.entity.id)
      .filter(id => id !== entityChange.entity.id),
  )

  if (directDependents.size === 0) {
    return { delta: -10, factor: 'no direct dependents found in graph' }
  }

  let unresolved = 0
  for (const dependentId of directDependents) {
    if (!changedEntityIds.has(dependentId)) {
      unresolved += 1
    }
  }

  if (unresolved === 0) {
    return { delta: -15, factor: 'all direct dependents also changed in this PR' }
  }

  const penalty = Math.min(20, 10 + (unresolved - 1) * 3)
  const label = unresolved === 1 ? '1 direct dependent not updated in this PR' : `${unresolved} direct dependents not updated in this PR`
  return { delta: penalty, factor: label }
}

interface FileChange {
  filepath: string
  status: 'added' | 'modified' | 'deleted' | 'renamed'
  oldFilepath?: string // for renames
  hunks: Hunk[]
}

interface Hunk {
  oldStart: number
  oldCount: number
  newStart: number
  newCount: number
}

interface EntityChange {
  entity: Entity
  changeKind: ChangeKind
  fileStatus: FileChange['status']
}

interface RiskSignal {
  entity: Entity
  score: number          // 0–100
  factors: string[]      // human-readable explanations
}

interface ImpactGap {
  seed: Entity
  seedChangeKind: ChangeKind
  directDependents: Entity[]
  unresolvedDependents: Entity[]
}

interface PRReview {
  summary: string
  changedEntities: EntityChange[]
  blastRadius: {
    direct: BlastRadiusEntry[]      // depth 1
    transitive: BlastRadiusEntry[]  // depth 2+
    totalFiles: number
    totalEntities: number
  }
  risks: RiskSignal[]               // sorted by score desc
  impactGaps: ImpactGap[]           // contract changes with unresolved dependents
  deadCode: Entity[]                // new unused exports
}

async function dependentsOf(
  sql: Sql,
  entityId: string,
  entityKind: EntityKind
): Promise<Entity[]> {
  let rows: EntityRow[]

  switch (entityKind) {
    case 'file':
      // Who imports entities from this file?
      rows = await sql<EntityRow[]>`
        SELECT DISTINCT e.* FROM entity_graph.entities e
        JOIN entity_graph.imports i ON i.importer_id = e.id
        WHERE i.imported_id = ${entityId}
      `
      break

    case 'function':
    case 'method':
      // Who calls this?
      rows = await sql<EntityRow[]>`
        SELECT DISTINCT e.* FROM entity_graph.entities e
        JOIN entity_graph.calls c ON c.caller_id = e.id
        WHERE c.callee_id = ${entityId}
      `
      break

    case 'type':
    case 'interface':
      // Who uses, imports, or implements this?
      rows = await sql<EntityRow[]>`
        SELECT DISTINCT e.* FROM entity_graph.entities e
        WHERE e.id IN (
          SELECT user_id FROM entity_graph.uses WHERE used_id = ${entityId}
          UNION
          SELECT implementor_id FROM entity_graph.implements WHERE interface_id = ${entityId}
          UNION
          SELECT importer_id FROM entity_graph.imports WHERE imported_id = ${entityId}
        )
      `
      break

    case 'class':
      // Who extends, imports, or uses this?
      rows = await sql<EntityRow[]>`
        SELECT DISTINCT e.* FROM entity_graph.entities e
        WHERE e.id IN (
          SELECT child_id FROM entity_graph.extends WHERE parent_id = ${entityId}
          UNION
          SELECT importer_id FROM entity_graph.imports WHERE imported_id = ${entityId}
        )
      `
      break

    default:
      rows = []
  }

  return rows.map(rowToEntity)
}

async function entitiesAtLines(
  sql: Sql,
  filepath: string,
  ranges: Array<{ startLine: number; endLine: number }>,
): Promise<Entity[]> {
  if (ranges.length === 0) return []

  // Build OR clause for overlapping ranges:
  // entity overlaps range when entity.start_line <= range.end AND entity.end_line >= range.start
  const conditions = ranges
    .map((_, i) => `(e.start_line <= $${i * 2 + 3} AND e.end_line >= $${i * 2 + 2})`)
    .join(' OR ')

  const params: (string | number)[] = [filepath]
  for (const r of ranges) {
    params.push(r.startLine, r.endLine)
  }

  const query = `
    SELECT DISTINCT e.* FROM entity_graph.entities e
    WHERE e.filepath = $1
      AND e.kind != 'file'
      AND (${conditions})
    ORDER BY e.start_line ASC NULLS LAST
  `
  const rows = await sql.unsafe<EntityRow[]>(query, params)
  return rows.map(rowToEntity)
}

interface BlastRadiusEntry {
  entity: Entity
  depth: number
  via: EdgeType
  seedId: string
}

function makeEntity(overrides: Partial<Entity> & { id: string; kind: Entity['kind']; name: string; filepath: string }): Entity {
  return {
    startLine: null,
    endLine: null,
    exported: false,
    async: false,
    rawText: null,
    ...overrides,
  }
}

function mockSql(entitiesByFile: Record<string, Entity[]>) {
  // Template tag handler (for entitiesInFile/entityById style queries)
  const handler = function (strings: TemplateStringsArray, ...values: unknown[]) {
    const query = strings.join('?')
    // entitiesInFile: WHERE filepath = <value>
    if (query.includes('FROM entity_graph.entities WHERE filepath')) {
      const filepath = values[0] as string
      return Promise.resolve((entitiesByFile[filepath] ?? []).map(entityToRow))
    }
    return Promise.resolve([])
  } as any

  // sql.unsafe handler (for entitiesAtLines dynamic query)
  handler.unsafe = (query: string, params: unknown[]) => {
    if (query.includes('FROM entity_graph.entities e') && query.includes('start_line')) {
      const filepath = params[0] as string
      const entities = entitiesByFile[filepath] ?? []
      // Filter to non-file entities (the real query excludes kind='file')
      const nonFile = entities.filter(e => e.kind !== 'file')

      // Extract line ranges from params (pairs after filepath)
      const ranges: Array<{ startLine: number; endLine: number }> = []
      for (let i = 1; i < params.length; i += 2) {
        ranges.push({ startLine: params[i] as number, endLine: params[i + 1] as number })
      }

      // Filter entities that overlap any range
      const result = nonFile.filter(e => {
        if (e.startLine == null || e.endLine == null) return false
        return ranges.some(r => e.startLine! <= r.endLine && e.endLine! >= r.startLine)
      })
      return Promise.resolve(result.map(entityToRow))
    }
    return Promise.resolve([])
  }

  return handler
}

function entityToRow(e: Entity) {
  return {
    id: e.id,
    kind: e.kind,
    name: e.name,
    filepath: e.filepath,
    start_line: e.startLine,
    end_line: e.endLine,
    exported: e.exported,
    async: e.async,
    raw_text: e.rawText,
  }
}

