interface FileChange {
  filepath: string
  status: 'added' | 'modified' | 'deleted' | 'renamed'
  oldFilepath?: string // for renames
  hunks: Hunk[]
}

interface Hunk {
  oldStart: number
  oldCount: number
  newStart: number
  newCount: number
}

interface ImpactGap {
