interface PRReview {
  summary: string
  changedEntities: EntityChange[]
  blastRadius: {
    direct: BlastRadiusEntry[]      // depth 1
    transitive: BlastRadiusEntry[]  // depth 2+
    totalFiles: number
    totalEntities: number
  }
  risks: RiskSignal[]               // sorted by score desc
  impactGaps: ImpactGap[]           // contract changes with unresolved dependents
  deadCode: Entity[]                // new unused exports
}

interface RiskSignal {
  entity: Entity
  score: number          // 0–100
  factors: string[]      // human-readable explanations
}

function parseFileDiff(
  lines: string[],
  start: number,
): { change: FileChange | null; nextIndex: number } {
  let i = start

  // Parse "diff --git a/path b/path"
  const diffLine = lines[i]
  const gitMatch = diffLine.match(/^diff --git a\/(.+) b\/(.+)$/)
  if (!gitMatch) return { change: null, nextIndex: i + 1 }

  const aPath = gitMatch[1]
  const bPath = gitMatch[2]
  i++

  // Consume metadata lines (old mode, new mode, similarity, index, etc.)
  let status: FileChange['status'] = 'modified'
  let oldFilepath: string | undefined

  while (i < lines.length && !lines[i].startsWith('diff --git ')) {
    const line = lines[i]

    if (line.startsWith('new file mode')) {
      status = 'added'
    } else if (line.startsWith('deleted file mode')) {
      status = 'deleted'
    } else if (line.startsWith('rename from ')) {
      status = 'renamed'
      oldFilepath = line.slice('rename from '.length)
    } else if (line.startsWith('--- ') || line.startsWith('+++ ')) {
      // Skip --- / +++ lines, handled by hunk parsing
    } else if (line.startsWith('@@')) {
      break // Start of hunks
    }
    i++
  }

  // Parse hunks
  const hunks: Hunk[] = []
  while (i < lines.length && !lines[i].startsWith('diff --git ')) {
    if (lines[i].startsWith('@@')) {
      const hunk = parseHunkHeader(lines[i])
      if (hunk) hunks.push(hunk)
    }
    i++
  }

  return {
    change: {
      filepath: bPath,
      status,
      oldFilepath,
      hunks,
    },
    nextIndex: i,
  }
}

function parseHunkHeader(line: string): Hunk | null {
  const match = line.match(/^@@ -(\d+)(?:,(\d+))? \+(\d+)(?:,(\d+))? @@/)
  if (!match) return null

  return {
    oldStart: parseInt(match[1], 10),
    oldCount: match[2] !== undefined ? parseInt(match[2], 10) : 1,
    newStart: parseInt(match[3], 10),
    newCount: match[4] !== undefined ? parseInt(match[4], 10) : 1,
  }
}

function inferChangeKind(
  entity: Entity,
  ranges: Array<{ startLine: number; endLine: number }>,
): ChangeKind {
  const start = entity.startLine ?? 0
  const exportLine = start          // `export function foo(` lives here
  const sigEnd = start + 2          // signature ≈ first 3 lines

  const touchesExportLine = ranges.some(
    r => r.startLine <= exportLine && r.endLine >= exportLine,
  )

  const touchesSignature = ranges.some(
    r => r.startLine <= sigEnd && r.endLine >= start,
  )

  const touchesBeyondExportLine = ranges.some(
    r => r.endLine > exportLine,
  )

  // Exported entity, hunk only on the export/declaration line itself
  if (entity.exported && touchesExportLine && !touchesBeyondExportLine) {
    return 'export_changed'
  }

  if (touchesSignature) {
    return 'signature_changed'
  }

  return 'body_changed'
}

function syntheticFileEntity(filepath: string): Entity {
  return {
    id: `file:${filepath}:${filepath}`,
    kind: 'file',
    name: filepath,
    filepath,
    startLine: null,
    endLine: null,
    exported: false,
    async: false,
    rawText: null,
  }
}

function buildSummary(
  changed: number,
  directCount: number,
  transitiveCount: number,
  risks: Array<{ score: number }>,
  impactGaps: ImpactGap[],
): string {
  const critical = risks.filter(r => r.score >= 70).length
  const warnings = risks.filter(r => r.score >= 40 && r.score < 70).length
  const unresolvedCount = impactGaps.reduce((sum, gap) => sum + gap.unresolvedDependents.length, 0)

  const parts: string[] = [
    `${changed} entit${changed === 1 ? 'y' : 'ies'} changed`,
  ]

  if (directCount > 0 || transitiveCount > 0) {
    parts.push(`${directCount} direct and ${transitiveCount} transitive dependents affected`)
  }

  if (critical > 0) {
    parts.push(`${critical} critical risk${critical === 1 ? '' : 's'}`)
  }
  if (warnings > 0) {
    parts.push(`${warnings} warning${warnings === 1 ? '' : 's'}`)
  }
  if (impactGaps.length > 0) {
    parts.push(
      `${impactGaps.length} contract gap${impactGaps.length === 1 ? '' : 's'} (${unresolvedCount} unresolved dependent${unresolvedCount === 1 ? '' : 's'})`,
    )
  }

  return parts.join('; ') + '.'
}

function computeImpactGaps(
  changedEntities: EntityChange[],
  blastEntries: Awaited<ReturnType<typeof entityBlastRadius>>,
): ImpactGap[] {
  const changedEntityIds = new Set(changedEntities.map(ec => ec.entity.id))
  const changesByEntityId = new Map(changedEntities.map(ec => [ec.entity.id, ec] as const))

  const directDependentsBySeed = new Map<string, Map<string, typeof blastEntries[number]['entity']>>()
  for (const entry of blastEntries) {
    if (entry.depth !== 1) continue
    if (entry.entity.id === entry.seedId) continue
    let dependents = directDependentsBySeed.get(entry.seedId)
    if (!dependents) {
      dependents = new Map()
      directDependentsBySeed.set(entry.seedId, dependents)
    }
    if (!dependents.has(entry.entity.id)) {
      dependents.set(entry.entity.id, entry.entity)
    }
  }

  const gaps: ImpactGap[] = []
  for (const changed of changedEntities) {
    if (!CONTRACT_CHANGE_KINDS.has(changed.changeKind)) continue
    const directDependents = Array.from(directDependentsBySeed.get(changed.entity.id)?.values() ?? [])
    if (directDependents.length === 0) continue
    const unresolved = directDependents.filter(dep => !changedEntityIds.has(dep.id))
    if (unresolved.length === 0) continue

    gaps.push({
      seed: changed.entity,
      seedChangeKind: changesByEntityId.get(changed.entity.id)?.changeKind ?? changed.changeKind,
      directDependents,
      unresolvedDependents: unresolved,
    })
  }

  gaps.sort((a, b) => b.unresolvedDependents.length - a.unresolvedDependents.length || a.seed.id.localeCompare(b.seed.id))
  return gaps
}

function dedupeBlastEntries(entries: Awaited<ReturnType<typeof entityBlastRadius>>): Awaited<ReturnType<typeof entityBlastRadius>> {
  const byEntity = new Map<string, typeof entries[number]>()

  for (const entry of entries) {
    const existing = byEntity.get(entry.entity.id)
    if (!existing || entry.depth < existing.depth) {
      byEntity.set(entry.entity.id, entry)
      continue
    }
    if (entry.depth === existing.depth && entry.via < existing.via) {
      byEntity.set(entry.entity.id, entry)
    }
  }

  return Array.from(byEntity.values()).sort(
    (a, b) => a.depth - b.depth || a.entity.filepath.localeCompare(b.entity.filepath) || a.entity.id.localeCompare(b.entity.id),
  )
}

function dedupeEntitiesById<T extends { id: string }>(items: T[]): T[] {
  const map = new Map<string, T>()
  for (const item of items) {
    if (!map.has(item.id)) map.set(item.id, item)
  }
  return Array.from(map.values())
}

function contractCoverageAdjustment(
  entityChange: EntityChange,
  blastEntries: BlastRadiusEntry[],
  changedEntityIds: Set<string>,
): { delta: number; factor: string | null } {
  if (!CONTRACT_CHANGE_KINDS.has(entityChange.changeKind)) {
    return { delta: 0, factor: null }
  }

  const directDependents = new Set(
    blastEntries
      .filter(entry => entry.seedId === entityChange.entity.id && entry.depth === 1)
      .map(entry => entry.entity.id)
      .filter(id => id !== entityChange.entity.id),
  )

  if (directDependents.size === 0) {
    return { delta: -10, factor: 'no direct dependents found in graph' }
  }

  let unresolved = 0
  for (const dependentId of directDependents) {
    if (!changedEntityIds.has(dependentId)) {
      unresolved += 1
    }
  }

  if (unresolved === 0) {
    return { delta: -15, factor: 'all direct dependents also changed in this PR' }
  }

  const penalty = Math.min(20, 10 + (unresolved - 1) * 3)
  const label = unresolved === 1 ? '1 direct dependent not updated in this PR' : `${unresolved} direct dependents not updated in this PR`
  return { delta: penalty, factor: label }
}

function seedSeverityByEntity(
  changedEntities: EntityChange[],
): Map<string, { raw: number; factor: string | null }> {
  const map = new Map<string, { raw: number; factor: string | null }>()

  for (const ec of changedEntities) {
    const raw = CHANGE_SEVERITY[ec.changeKind] ?? 0
    const existing = map.get(ec.entity.id)
    if (existing && existing.raw >= raw) continue
    map.set(ec.entity.id, {
      raw,
      factor: `upstream ${ec.changeKind.replace(/_/g, ' ')} in ${ec.entity.name}`,
    })
  }

  return map
}

function uniqueFactors(factors: string[]): string[] {
  return Array.from(new Set(factors))
}

function upstreamSeverityForEntry(
  entry: BlastRadiusEntry,
  seedSeverity: Map<string, { raw: number; factor: string | null }>,
  fallbackWorst: { score: number; factor: string | null },
): { score: number; factor: string | null } {
  const seed = seedSeverity.get(entry.seedId)
  if (!seed) return fallbackWorst
  return { score: Math.round(seed.raw * 0.5), factor: seed.factor }
}

function worstUpstreamSeverity(
  changedEntities: EntityChange[],
): { score: number; factor: string | null } {
  let worst = 0
  let factor: string | null = null

  for (const ec of changedEntities) {
    const s = CHANGE_SEVERITY[ec.changeKind] ?? 0
    if (s > worst) {
      worst = s
      factor = `upstream ${ec.changeKind.replace(/_/g, ' ')} in ${ec.entity.name}`
    }
  }

  return { score: Math.round(worst * 0.5), factor }
}

function entityToRow(e: Entity) {
  return {
    id: e.id,
    kind: e.kind,
    name: e.name,
    filepath: e.filepath,
    start_line: e.startLine,
    end_line: e.endLine,
    exported: e.exported,
    async: e.async,
    raw_text: e.rawText,
  }
}

function makeEntity(overrides: Partial<Entity> & { id: string; kind: Entity['kind']; name: string; filepath: string }): Entity {
  return {
    startLine: null,
    endLine: null,
    exported: false,
    async: false,
    rawText: null,
    ...overrides,
  }
}

function mockSql(entitiesByFile: Record<string, Entity[]>) {
  // Template tag handler (for entitiesInFile/entityById style queries)
  const handler = function (strings: TemplateStringsArray, ...values: unknown[]) {
    const query = strings.join('?')
    // entitiesInFile: WHERE filepath = <value>
    if (query.includes('FROM entity_graph.entities WHERE filepath')) {
      const filepath = values[0] as string
      return Promise.resolve((entitiesByFile[filepath] ?? []).map(entityToRow))
    }
    return Promise.resolve([])
  } as any

  // sql.unsafe handler (for entitiesAtLines dynamic query)
  handler.unsafe = (query: string, params: unknown[]) => {
    if (query.includes('FROM entity_graph.entities e') && query.includes('start_line')) {
      const filepath = params[0] as string
      const entities = entitiesByFile[filepath] ?? []
      // Filter to non-file entities (the real query excludes kind='file')
      const nonFile = entities.filter(e => e.kind !== 'file')

      // Extract line ranges from params (pairs after filepath)
      const ranges: Array<{ startLine: number; endLine: number }> = []
      for (let i = 1; i < params.length; i += 2) {
        ranges.push({ startLine: params[i] as number, endLine: params[i + 1] as number })
      }

      // Filter entities that overlap any range
      const result = nonFile.filter(e => {
        if (e.startLine == null || e.endLine == null) return false
        return ranges.some(r => e.startLine! <= r.endLine && e.endLine! >= r.startLine)
      })
      return Promise.resolve(result.map(entityToRow))
    }
    return Promise.resolve([])
  }

  return handler
}

function makeEntity(overrides: Partial<Entity> & { id: string; kind: Entity['kind']; name: string; filepath: string }): Entity {
  return {
    startLine: null,
    endLine: null,
    exported: false,
    async: false,
    rawText: null,
    ...overrides,
  }
}

