  newStart: number
  newCount: number
}

interface EntityChange {
  entity: Entity
  changeKind: ChangeKind
  fileStatus: FileChange['status']
}

interface RiskSignal {
  entity: Entity
  score: number          // 0–100
  factors: string[]      // human-readable explanations
}

interface ImpactGap {
  seed: Entity
  seedChangeKind: ChangeKind
